// ── Schema-aware tree builder ──

export function buildKSCTree(root: KSNode): KSCDNode {
  function build(
    raw: KSNode,
    parent: KSCDNode | undefined,
    fieldName: string | undefined,
  ): KSCDNode {
    const children: KSCDNode[] = [];
    const dnode = new KSCDNode(raw, parent, children, fieldName);

    const fields = getChildFields(raw.kind);
    for (const field of fields) {
      const val = (raw as any)[field];
      if (val == null) continue;
      if (Array.isArray(val)) {
        for (const item of val) {
          if (item == null) continue;
          children.push(build(item as KSNode, dnode, field));
        }
      } else {
        children.push(build(val as KSNode, dnode, field));
      }
    }

    return dnode;
  }

  return build(root, undefined, undefined);
}

